changeSet.sql:
-- 1. GENERAL_CODES CREATE TABLE general_codes ( general_code VARCHAR(30) PRIMARY KEY, description TEXT );
-- 2. GENERAL_ENTRIES CREATE TABLE general_entries ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, general_code VARCHAR(30) NOT NULL, specific_code VARCHAR(30) NOT NULL, description TEXT, date_created TIMESTAMPTZ NOT NULL, date_updated TIMESTAMPTZ NOT NULL,
CONSTRAINT fk_general_entries_general_code FOREIGN KEY (general_code) REFERENCES general_codes (general_code),
CONSTRAINT unique_general_specific_code UNIQUE (general_code, specific_code) );
